svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var dataLayerEl = ctx.$$('#data-layer');
    var legendRoot = ctx.$$('#legend-root');
    var tip = ctx.$$('#tip');
    var stages = ctx.$$all('.fstage');
    var timing;
    var delays;
    var plotShiftX = 0;

    if (!dataLayerEl || !legendRoot || !tip || !stages.length) return;

    ctx.initStandardLegend({
      legendEl: legendRoot,
      title: 'SERIES',
      rowGap: 30,
      items: [
        { cls: 'series-1', label: 'Awareness', value: '48,200' },
        { cls: 'series-2', label: 'Interest', value: '28,900' },
        { cls: 'series-3', label: 'Consideration', value: '14,600' },
        { cls: 'series-4', label: 'Intent', value: '7,840' },
        { cls: 'series-5', label: 'Evaluation', value: '3,920' },
        { cls: 'series-6', label: 'Purchase', value: '1,960' }
      ]
    });
    plotShiftX = ctx.rebalancePlotArea({
      legendEl: legendRoot,
      measureNodes: [dataLayerEl],
      moveNodes: [dataLayerEl],
      outerLeft: 24,
      legendGap: 32
    }).shiftX || 0;
    timing = ctx.getStaggerTiming(stages.length, null, svgEl);
    delays = stages.map(function (_, index) {
      return ctx.getStaggerDelay(index, stages.length, null, svgEl);
    });
    ctx.initRevealSequence(stages, {
      animationName: 'stageFade',
      duration: timing.duration,
      easing: 'ease-out',
      delays: delays
    });

    ctx.markReadyAfterReveal(dataLayerEl, {
      delays: delays,
      duration: timing.duration,
      buffer: timing.buffer
    });

    ctx.initStandardTooltip(dataLayerEl, stages, {
      leaveTarget: dataLayerEl,
      tip: tip,
      plotL: 68,
      plotR: 820,
      plotT: 100,
      plotB: 500,
      boxHeight: 120,
      minWidth: 220,
      paddingX: 20,
      paddingY: 18,
      lineHeights: [42, 32, 32],
      trackPointer: false,
      getContent: function (stageEl) {
        var dropoff = stageEl.getAttribute('data-dropoff') || '';
        return {
          primary: stageEl.getAttribute('data-val') || '',
          label: stageEl.getAttribute('data-name') || '',
          meta: dropoff ? (stageEl.getAttribute('data-pct') || '') + ' - ' + dropoff : (stageEl.getAttribute('data-pct') || '')
        };
      },
      getAnchor: function (stageEl) {
        return {
          x: parseFloat(stageEl.getAttribute('data-cx')) + plotShiftX,
          y: parseFloat(stageEl.getAttribute('data-cy'))
        };
      }
    });

    stages.forEach(function (stageEl) {
      stageEl.addEventListener('mouseenter', function () {
        dataLayerEl.classList.add('hovering');
        stages.forEach(function (otherStage) { otherStage.classList.remove('hovered'); });
        stageEl.classList.add('hovered');
      });
      stageEl.addEventListener('mouseleave', function () {
        stageEl.classList.remove('hovered');
      });
    });

    dataLayerEl.addEventListener('mouseleave', function () {
      dataLayerEl.classList.remove('hovering');
      stages.forEach(function (stageEl) { stageEl.classList.remove('hovered'); });
    });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
